import boto3
import logging
import os

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    # Extract bucket name and object key from the event
    bucket_name = event['Records'][0]['s3']['bucket']['name']
    object_key = event['Records'][0]['s3']['object']['key']
    
    # Log the event
    logger.info(f"Processing file {object_key} from bucket {bucket_name}")
    
    # Download the image from S3
    download_path = f"/tmp/{object_key}"
    s3_client.download_file(bucket_name, object_key, download_path)
    
    # Process the image (placeholder for image processing logic)
    processed_image_path = process_image(download_path)
    
    # Upload the processed image back to S3
    processed_bucket_name = os.environ['PROCESSED_BUCKET_NAME']
    s3_client.upload_file(processed_image_path, processed_bucket_name, object_key)
    
    # Send a notification via SNS
    sns_topic_arn = os.environ['SNS_TOPIC_ARN']
    sns_client.publish(
        TopicArn=sns_topic_arn,
        Message=f"Image {object_key} processed and uploaded to {processed_bucket_name}"
    )
    
    # Log completion
    logger.info(f"Image {object_key} processed and uploaded to {processed_bucket_name}")

